fs.mkdirSync(evidenceDir, { recursive: true });

const impactLines: string[] = [
  `=== H18 Impact Evidence ===`,
  `Timestamp: ${new Date().toISOString()}`,
  `Primary agent dir: ${primaryAgentDir}`,
  `Evil-agent dir (attacker-planted): ${evilAgentDir}`,
  ``,
  `--- Primary auth-profiles.json ---`,
  primaryExists ? fs.readFileSync(primaryAuthFile, "utf8") : "(not created)",
  ``,
  `--- Evil-agent auth-profiles.json (STOLEN) ---`,
  evilExists ? fs.readFileSync(evilAuthFile, "utf8") : "(not created)",
