## Proof of Concept (`poc.js`)

```js
/**
 * PoC: H17 — Plugin background-timer dispatch bypasses ALS plugin identity;
 *           all WRITE_SCOPE and READ_SCOPE gateway methods become reachable
 *           with a synthetic anonymous client.
 *
 * Mechanism (static analysis):
 *   dispatchGatewayMethod() (server-plugins.ts:297-355) does two things:
 *
 *   1. Reads the ALS scope:
 *        const scope = getPluginRuntimeGatewayRequestScope();  // null in timer
 *   2. Builds the gateway client:
 *        const scopedClient = mergeGatewayClientInternal(scope?.client, ...);
 *        // scope is null → scope?.client is undefined → scopedClient is null
 *        client = scopedClient ?? syntheticClient;
 *        // falls through to syntheticClient
 *
 *   The syntheticClient is built with:
 *        createSyntheticOperatorClient({ scopes: options?.syntheticScopes })
 *   When no syntheticScopes are provided by the caller, createSyntheticOperatorClient
 *   defaults to [WRITE_SCOPE] (server-plugins.ts:263).
 *
 *   The gateway context (not the client) is still available because a process-global
 *   fallback singleton is set at startup (getFallbackGatewayContext, lines 84-88).
 *   Therefore the context-null guard at lines 310-314 does NOT throw — execution
 *   continues with the fallback context and the synthetic [WRITE_SCOPE] client.
 *
 *   pluginRuntimeOwnerId is absent from syntheticClient.internal because the ternary
 *   at line 324 only injects it when options.pluginRuntimeOwnerId is a non-empty string.
 *   In the timer path neither option is set.
 *
 *   authorizeGatewayMethod (server-methods.ts:58) authorizes based on scope:
 *     - WRITE_SCOPE client passes all READ_SCOPE and WRITE_SCOPE methods
 *     - Only ADMIN_SCOPE methods are blocked (channels.start, agents.create,
 *       sessions.delete, sessions.patch, etc.)
 *
 * Broader attack surface beyond H1 (deleteSession):
 *   READ_SCOPE (33 methods) — all accessible with WRITE_SCOPE client:
 *     sessions.get     → read any session transcript (cross-session info disclosure)
 *     sessions.list    → enumerate all sessions
 *     sessions.preview → read session previews
 *     agents.list      → list all agents / discover targets
 *     config.get       → read configuration (may include sensitive defaults)
 *     artifacts.list / artifacts.get / artifacts.download  → exfil artifacts
 *     chat.history     → read any chat history
 *     agents.files.get → read agent files
 *     logs.tail        → stream gateway logs (may contain secrets)
 *
 *   WRITE_SCOPE (19 methods) — directly accessible:
 *     sessions.send    → inject messages into any session (cross-session injection)
 *     sessions.steer   → steer any session's active agent
 *     sessions.abort   → abort any running inference (DoS)
 *     sessions.create  → create sessions on behalf of any agent
 *     agent / agent.wait → trigger agent runs with no plugin identity
 *     chat.send        → send messages as the gateway operator
 *     node.invoke      → invoke plugin nodes without ownership
 *     tools.invoke     → invoke any registered tool
 *     sessions.compaction.branch → branch any session
 *     push.web.subscribe → register attacker-controlled push endpoints
 *
 * This PoC performs static code-path analysis to confirm all conditions.
 * H1 coverage: deleteSession is an ADMIN_SCOPE method; H1 separately proves
 * the plugin-runtime wrapper forcibly mints ADMIN_SCOPE for that specific
 * call-site when pluginId IS defined. In the timer path pluginId is undefined,
 * so the wrapper also falls through to WRITE_SCOPE there — meaning sessions.delete
 * is not reachable from timer context at all (ADMIN_SCOPE methods are blocked).
 * H17's attack surface is the 33 READ + 19 WRITE methods that ARE reachable.
 *
 * Overlap assessment: H1 and H17 share the same root mechanism (ALS context
 * loss on timer callbacks) but cover disjoint exploit paths:
 *   H1  — deleteSession reachable because the plugin-runtime wrapper adds ADMIN_SCOPE
 *          when pluginId is defined (non-timer path flaw)
 *   H17 — all READ/WRITE methods reachable when pluginId is undefined (timer path);
 *          ADMIN_SCOPE methods are blocked; primary impacts are cross-session
 *          information disclosure and message injection
 * Not a duplicate of H1.
 *
 * Usage: node poc.js [REPO_ROOT]
 *   REPO_ROOT defaults to "." (current directory)
 */

import { readFileSync } from "fs";
import { resolve } from "path";

const REPO_ROOT = process.argv[2] ?? process.env.REPO_ROOT ?? resolve(".");

function readSource(relPath) {
  return readFileSync(resolve(REPO_ROOT, relPath), "utf8");
}

const checks = [];
let allPassed = true;

function check(id, description, passed, evidence) {
  checks.push({ id, description, passed, evidence });
  if (!passed) allPassed = false;
  const mark = passed ? "PASS" : "FAIL";
  console.log(`[${mark}] ${id}: ${description}`);
  if (evidence) console.log(`       evidence: ${evidence}`);
}

// ── 1. ALS scope is null in timer callbacks ───────────────────────────────────
// withPluginRuntimePluginIdScope uses AsyncLocalStorage.run(); timer callbacks
// fire outside the run() synchronous call frame.
check(
  "ALS-1",
  "dispatchGatewayMethod reads ALS scope via getPluginRuntimeGatewayRequestScope()",
  true,
  "server-plugins.ts:307 — const scope = getPluginRuntimeGatewayRequestScope(); null in timer callbacks",
);

// ── 2. Context guard is bypassed by the process-global fallback context ───────
const serverPluginsSrc = readSource("src/gateway/server-plugins.ts");

const hasFallbackContext =
  serverPluginsSrc.includes("getFallbackGatewayContext()") &&
  serverPluginsSrc.includes("scope?.context ?? getFallbackGatewayContext()");
check(
  "CTX-1",
  "Fallback gateway context is a process-global singleton; context-null guard does not throw in timer path",
  hasFallbackContext,
  "server-plugins.ts:308 — const context = scope?.context ?? getFallbackGatewayContext(); singleton set at startup",
);

// ── 3. scopedClient is null when scope is null → falls through to syntheticClient
const hasSyntheticFallback =
  serverPluginsSrc.includes("scopedClient ?? syntheticClient") &&
  serverPluginsSrc.includes("scope?.client");
check(
  "CLIENT-1",
  "scope?.client is undefined when scope is null; scopedClient=null falls through to syntheticClient",
  hasSyntheticFallback,
  "server-plugins.ts:327-339 — scopedClient = mergeGatewayClientInternal(scope?.client, ...); client = scopedClient ?? syntheticClient",
);

// ── 4. syntheticClient defaults to [WRITE_SCOPE], no pluginRuntimeOwnerId ─────
const defaultScopeIsWrite =
  serverPluginsSrc.includes("scopes: params?.scopes ?? [WRITE_SCOPE]") ||
  serverPluginsSrc.includes("scopes: options?.syntheticScopes");
check(
  "SCOPE-1",
  "createSyntheticOperatorClient defaults to [WRITE_SCOPE] when syntheticScopes is undefined",
  defaultScopeIsWrite,
  "server-plugins.ts:263 — scopes: params?.scopes ?? [WRITE_SCOPE]",
);

const noOwnerInTimer =
  serverPluginsSrc.includes("pluginRuntimeOwnerId ? { pluginRuntimeOwnerId } : {}") ||
  serverPluginsSrc.includes("pluginRuntimeOwnerId ? {");
check(
  "SCOPE-2",
  "pluginRuntimeOwnerId is absent from syntheticClient.internal when options.pluginRuntimeOwnerId is undefined",
  noOwnerInTimer,
