class ExecApprovalManager {
  pending = new Map();

  create(request, timeoutMs, id) {
    const now = Date.now();
    const resolvedId = id ?? Math.random().toString(36).slice(2);
    return { id: resolvedId, request, createdAtMs: now, expiresAtMs: now + timeoutMs };
  }

  register(record, timeoutMs) {
    if (this.pending.has(record.id)) {
      const existing = this.pending.get(record.id);
      if (existing.record.resolvedAtMs === undefined) return existing.promise;
      throw new Error(`approval id '${record.id}' already resolved`);
    }
    let resolvePromise, rejectPromise;
    const promise = new Promise((res, rej) => { resolvePromise = res; rejectPromise = rej; });
    const entry = { record, resolve: resolvePromise, reject: rejectPromise, timer: null, promise };
    entry.timer = setTimeout(() => this.expire(record.id), timeoutMs);
    if (typeof entry.timer.unref === "function") entry.timer.unref();
    this.pending.set(record.id, entry);
    return promise;
  }

  resolve(recordId, decision, resolvedBy) {
    const pending = this.pending.get(recordId);
    if (!pending) return false;
    if (pending.record.resolvedAtMs !== undefined) return false;
    clearTimeout(pending.timer);
    pending.record.resolvedAtMs = Date.now();
    pending.record.decision = decision;
    pending.record.resolvedBy = resolvedBy ?? null;
    pending.resolve(decision);
    scheduleResolvedEntryCleanup(() => {
      if (this.pending.get(recordId) === pending) this.pending.delete(recordId);
    });
    return true;
  }

  expire(recordId, resolvedBy) {
    const pending = this.pending.get(recordId);
    if (!pending) return false;
    if (pending.record.resolvedAtMs !== undefined) return false;
    clearTimeout(pending.timer);
    pending.record.resolvedAtMs = Date.now();
    pending.record.decision = undefined;
    pending.record.resolvedBy = resolvedBy ?? null;
    pending.resolve(null);
    scheduleResolvedEntryCleanup(() => {
      if (this.pending.get(recordId) === pending) this.pending.delete(recordId);
    });
    return true;
  }

  getSnapshot(recordId) {
    return this.pending.get(recordId)?.record ?? null;
  }

  // Exact replica of src/gateway/exec-approval-manager.ts:174-188
  consumeAllowOnce(recordId) {
    const entry = this.pending.get(recordId);
    if (!entry) return false;
    const record = entry.record;
    if (record.decision !== "allow-once") return false;  // line 180
