 */
function simulateApproveLoop(requestedRoles, pendingScopes, callerScopes) {
  const results = [];
  const nextTokenScopesByRole = new Map();

  for (const roleForToken of requestedRoles) {
    const nextScopes = resolveApprovedTokenScopes(roleForToken, pendingScopes);
    nextTokenScopesByRole.set(roleForToken, nextScopes);

    // --- BEGIN: exact replication of L616-632 ---
    if (roleForToken === OPERATOR_ROLE && nextScopes.length > 0) {
      if (!callerScopes) {
