"use strict";

// ──────────────────────────────────────────────────────────────────────────────
// Verbatim logic from src/gateway/server-shared-auth-generation.ts
// ──────────────────────────────────────────────────────────────────────────────

function getRequiredSharedGatewaySessionGeneration(state) {
  return state.required === null ? state.current : state.required;
}

function setCurrentSharedGatewaySessionGeneration(state, nextGeneration) {
  const previousGeneration = state.current;
  state.current = nextGeneration;
  if (state.required === nextGeneration) {
    state.required = null;
    return;
  }
  if (state.required !== null && previousGeneration !== nextGeneration) {
    state.required = null;
  }
}

// ──────────────────────────────────────────────────────────────────────────────
// Minimal WS handshake simulator
// ──────────────────────────────────────────────────────────────────────────────

/**
 * Simulates message-handler.ts:841-856 (generation check at handshake time)
 * and message-handler.ts:1319-1323 (recording sharedGatewaySessionGeneration
 * into GatewayWsClient).
 *
 * Returns { accepted: boolean, recordedGeneration: string|undefined }
 */
function simulateHandshake(state, clientTokenGeneration) {
  const required = getRequiredSharedGatewaySessionGeneration(state);
  // message-handler.ts:847-856
  if (required !== undefined && clientTokenGeneration !== required) {
    return { accepted: false, recordedGeneration: undefined, rejectReason: "generation-mismatch" };
  }
  // message-handler.ts:1321-1323 — recorded at registration time
  const recordedGeneration = clientTokenGeneration;
  return { accepted: true, recordedGeneration };
}

/**
 * Simulates message-handler.ts:1554-1567 (per-message generation check).
 */
function simulatePerMessageCheck(state, client) {
  if (!client.usesSharedGatewayAuth) return { pass: true };
  const required = getRequiredSharedGatewaySessionGeneration(state);
  if (required !== undefined && client.recordedGeneration !== required) {
    return { pass: false, reason: "auth-generation-stale" };
  }
  return { pass: true };
}

// ──────────────────────────────────────────────────────────────────────────────
// Race scenario driver
// ──────────────────────────────────────────────────────────────────────────────

function runRaceScenario({ applyHotReloadFails }) {
  const label = applyHotReloadFails ? "OUTCOME-2 (rollback race)" : "OUTCOME-1 (happy-path race)";
  console.log(`\n=== ${label} ===`);

  // Initial state: required=null means "use current as the enforced generation"
  // (null sentinel: server-shared-auth-generation.ts:52)
  const state = { current: "gen-OLD", required: null };
  const OLD_GEN = "gen-OLD";
  const NEW_GEN = "gen-NEW";

  console.log(`[initial]   state = ${JSON.stringify(state)}`);

  // ── server-reload-handlers.ts:518 ────────────────────────────────────────
  // Write 1: direct mutation of .current BEFORE await applyHotReload
  state.current = NEW_GEN;
  console.log(`[L518 write-1]  state.current = "${NEW_GEN}" → state = ${JSON.stringify(state)}`);

  // ── async gap (await applyHotReload) ─────────────────────────────────────
  // A new WS connect races in here.  The attacker token resolves to NEW_GEN.
  const racingClient = { usesSharedGatewayAuth: true };
  const handshakeResult = simulateHandshake(state, NEW_GEN);
  Object.assign(racingClient, { recordedGeneration: handshakeResult.recordedGeneration });
  console.log(
    `[gap handshake] clientGen="${NEW_GEN}" required="${getRequiredSharedGatewaySessionGeneration(state)}" → accepted=${handshakeResult.accepted} recordedGen="${racingClient.recordedGeneration}"`,
  );

  if (!handshakeResult.accepted) {
    console.log("[gap handshake] Connection rejected — race window closed");
    return { exploited: false };
  }

  if (applyHotReloadFails) {
    // ── server-reload-handlers.ts:535 — rollback ─────────────────────────
    state.current = OLD_GEN;
    console.log(`[L535 rollback] state.current = "${OLD_GEN}" → state = ${JSON.stringify(state)}`);
    // required stays null (rollback does NOT call setCurrentSharedGatewaySessionGeneration)

    const perMsg = simulatePerMessageCheck(state, racingClient);
    console.log(
      `[per-message]   required="${getRequiredSharedGatewaySessionGeneration(state)}" clientGen="${racingClient.recordedGeneration}" → pass=${perMsg.pass} reason=${perMsg.reason ?? "n/a"}`,
    );
    // After rollback, required is still null so getRequired returns OLD_GEN.
    // Client recorded NEW_GEN → per-message check will reject.
    // BUT: IDENTIFY frame already processed during the gap — one live frame.
    const identifyAlreadyProcessed = true;
    console.log(
      `[impact] IDENTIFY processed during gap = ${identifyAlreadyProcessed}; subsequent frames rejected = ${!perMsg.pass}`,
    );
    return {
      exploited: identifyAlreadyProcessed && !perMsg.pass,
      detail: "one IDENTIFY frame processed on orphaned session before per-message rejection",
    };
  } else {
    // ── server-reload-handlers.ts:544 ────────────────────────────────────
    // Write 2: setCurrentSharedGatewaySessionGeneration clears required
    setCurrentSharedGatewaySessionGeneration(state, NEW_GEN);
    console.log(
      `[L544 write-2]  setCurrentSharedGatewaySessionGeneration("${NEW_GEN}") → state = ${JSON.stringify(state)}`,
    );

    const perMsg = simulatePerMessageCheck(state, racingClient);
    console.log(
      `[per-message]   required="${getRequiredSharedGatewaySessionGeneration(state)}" clientGen="${racingClient.recordedGeneration}" → pass=${perMsg.pass}`,
    );
    // required=null → getRequired returns NEW_GEN; client gen = NEW_GEN → pass
    // Connection fully survives; missed by disconnectStaleSharedGatewayAuthClients
    // at L522 (ran before this client connected).
    return {
      exploited: perMsg.pass && handshakeResult.accepted,
      detail:
        "connection with NEW_GEN token accepted during gap, survives all checks; stale-disconnect sweep at L522 already ran against prior client set",
    };
  }
}

// ──────────────────────────────────────────────────────────────────────────────
// Main
// ──────────────────────────────────────────────────────────────────────────────

const results = [];

const r1 = runRaceScenario({ applyHotReloadFails: false });
results.push({ scenario: "happy-path race", ...r1 });

const r2 = runRaceScenario({ applyHotReloadFails: true });
results.push({ scenario: "rollback race", ...r2 });

console.log("\n=== Summary ===");
for (const r of results) {
  console.log(`  ${r.scenario}: exploited=${r.exploited} — ${r.detail}`);
}

const anyExploited = results.some((r) => r.exploited);

// Structured output contract — MUST be last stdout line
console.log(
  JSON.stringify({
    status: anyExploited ? "confirmed" : "failed",
    evidence: anyExploited
      ? "racing WS handshake accepted during L518→L544 async gap; connection survives disconnectStaleSharedGatewayAuthClients sweep; one IDENTIFY frame processed on orphaned session in rollback path"
      : "no exploitable window detected",
    notes:
      "static-analysis / state-machine simulation; PoC-Status=theoretical; dynamic confirmation requires instrumented applyHotReload + racing WS connect in test harness",
  }),
);
